	@Test
	void plansBothAssociationsOfAChain() {
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 1000);
		int b = planGraph.addNode("B", 1);
		int c = planGraph.addNode("C", 1000);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 0.001d, "A.k=B.k");
		planGraph.addJoinEdge(NodeSets.bit(b), NodeSets.bit(c), 0.001d, "B.k=C.k");

		CostingReceiver receiver = run(planGraph, CostModel.DEFAULT);

		assertNotNull(receiver.planFor(NodeSets.bit(a) | NodeSets.bit(b)), "must have planned {A,B}");
		assertNotNull(receiver.planFor(NodeSets.bit(b) | NodeSets.bit(c)), "must have planned {B,C}");
		assertNull(receiver.planFor(NodeSets.bit(a) | NodeSets.bit(c)), "{A,C} is a Cartesian product");
		JoinPlan best = receiver.planFor(planGraph.graph().allNodes());
		assertNotNull(best);
		assertEquals(1.0d, best.rows(), 1e-9, "1000 * 1 * 1000 * 0.001 * 0.001");
	}

