	private static double rowsForAssociation(PlanHypergraph planGraph, int leftNode, int rightNode, int finalNode) {
		CostingReceiver receiver = new CostingReceiver(planGraph, CostModel.DEFAULT, Long.MAX_VALUE);
		receiver.foundSingleNode(leftNode);
		receiver.foundSingleNode(rightNode);
		receiver.foundSingleNode(finalNode);
		long left = NodeSets.bit(leftNode);
		long right = NodeSets.bit(rightNode);
		receiver.foundSubgraphPair(left, right, 0);
		receiver.foundSubgraphPair(left | right, NodeSets.bit(finalNode), 0);
		return receiver.planFor(planGraph.graph().allNodes()).rows();
	}

	@Test
	void hyperpredicateAppliesAtTheFirstJoinCoveringItsTes() {
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 10);
		int b = planGraph.addNode("B", 10);
		int c = planGraph.addNode("C", 10);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 0.01d, "ab");
		planGraph.addJoinEdge(NodeSets.bit(b), NodeSets.bit(c), 0.01d, "bc");
		planGraph.addPredicate(NodeSets.bit(a) | NodeSets.bit(b) | NodeSets.bit(c), 0.5d, "a+b>c");

		CostingReceiver receiver = run(planGraph, CostModel.DEFAULT);

		JoinPlan ab = receiver.planFor(NodeSets.bit(a) | NodeSets.bit(b));
		assertEquals(1.0d, ab.rows(), 1e-9, "hyperpredicate must not fire on {A,B}");
		JoinPlan full = receiver.planFor(planGraph.graph().allNodes());
		assertEquals(10 * 10 * 10 * 0.01d * 0.01d * 0.5d, full.rows(), 1e-9,
				"hyperpredicate applied exactly once at the top");
	}

	@Test
	void nestedLoopWinsWhenLookupIsCheap() {
		PlanHypergraph planGraph = new PlanHypergraph();
		int a = planGraph.addNode("A", 10);
		int b = planGraph.addNode("B", 1_000_000);
		planGraph.addJoinEdge(NodeSets.bit(a), NodeSets.bit(b), 1e-6d, "ab");

		CostModel lookupModel = new CostModel() {
			@Override
			public double scanCost(int nodeIdx, double cardinality) {
				return cardinality;
			}

			@Override
			public double hashJoinCost(double probeRows, double buildRows, double outputRows) {
				return 2.0d * buildRows + probeRows + 0.5d * outputRows;
			}

			@Override
			public double nestedLoopLookupCost(int nodeIdx, long boundNodes, double outerRows) {
				return nodeIdx == 1 ? outerRows * 2.0d : Double.NaN;
			}
		};
		CostingReceiver receiver = run(planGraph, lookupModel);
		JoinPlan best = receiver.planFor(planGraph.graph().allNodes());
		assertEquals(JoinPlan.Kind.NESTED_LOOP, best.kind(), best.toString());
		assertEquals(0, best.left().scanNode(), "A must be the outer side");
		assertEquals(10.0d + 10.0d * 2.0d, best.cost(), 1e-9, "scan A plus ten lookups into B");
		assertEquals(10.0d, best.rows(), 1e-9, "rows stay canonical: 10 * 1e6 * 1e-6");
	}

